mapper.select:
SELECT r.id, r.route_title_zh, r.pic_url
, fav.favorite_flg
FROM yy_route r JOIN ( SELECT target_id, COUNT(*) cnt FROM yy_user_favorite WHERE target_kbn='03' AND user_type='01' AND favorite_flg='1' AND create_time >= DATE_SUB(NOW(), INTERVAL #{days} DAY) GROUP BY target_id ORDER BY cnt DESC LIMIT #{topNums} ) t ON r.id = t.target_id
left outer join yy_user_favorite fav on r.id = fav.target_id and target_kbn = '03' and user_type = '01' and user_id = #{customerId}
ORDER BY t.cnt DESC;

SELECT *
FROM yy_user_favorite
WHERE target_kbn='03'
    AND target_id = #{targetId}
    AND user_type ='01'
    AND user_id = #{userId}
